import React from "react";
import { useLocation } from "react-router-dom";
import { getInitials } from "../utils/helpers";

const PAGE_TITLES = {
  "/admin-dashboard": "Admin Dashboard",
  "/volunteer-dashboard": "Volunteer Dashboard",
  "/needs": "Community Needs",
  "/volunteers": "Volunteers",
  "/map": "Map View",
  "/matching": "Smart Match",
  "/submit-need": "Submit Need",
  "/add-volunteer": "Add Volunteer",
};

export default function Topbar({ user, urgentCount, availableCount, onSeed, seeding, onLogout }) {
  const location = useLocation();
  const title = PAGE_TITLES[location.pathname] || "ReliefLink";
  const isAdmin = user?.role === "admin";

  return (
    <header className="topbar">
      <div className="topbar-left">
        <h2 style={{ fontSize: 20, fontWeight: 700, color: "#1e293b" }}>{title}</h2>
      </div>

      <div className="topbar-right" style={{ display: "flex", gap: 16, alignItems: "center" }}>
        {isAdmin && onSeed && (
          <button className="btn btn-outline btn-sm" onClick={onSeed} disabled={seeding} style={{ fontSize: 11 }}>
            {seeding ? "Seeding..." : "⚡ Seed Sample Data"}
          </button>
        )}

        <div style={{ display: "flex", gap: 8 }}>
          {urgentCount > 0 && (
            <span className="badge" style={{ background: "#fee2e2", color: "#dc2626", fontSize: 11, fontWeight: 600 }}>
              ⚠ {urgentCount} Urgent
            </span>
          )}
          <span className="badge" style={{ background: "#dcfce7", color: "#16a34a", fontSize: 11, fontWeight: 600 }}>
            {availableCount} Available
          </span>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 12, borderLeft: "1px solid #e2e8f0", paddingLeft: 16, marginLeft: 8 }}>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: "#1e293b", lineHeight: 1.2 }}>{user?.name || "User"}</div>
            <div style={{ fontSize: 10, color: "#64748b", textTransform: "capitalize" }}>{user?.role}</div>
          </div>
          <div style={{ width: 32, height: 32, borderRadius: "50%", background: "#e2e8f0", color: "#475569", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700 }}>
            {getInitials(user?.name || user?.email || "U")}
          </div>
          <button 
            className="btn btn-sm" 
            onClick={onLogout}
            style={{ fontSize: 11, padding: "4px 8px", background: "#f1f5f9", color: "#475569", borderColor: "#cbd5e1" }}
          >
            Logout
          </button>
        </div>
      </div>
    </header>
  );
}
